trigger.body:
    vCheck NUMBER;
BEGIN

    IF AD_isTriggerEnabled()='N' THEN RETURN;
    END IF;

    IF TG_OP IN ('INSERT', 'UPDATE') THEN
        SELECT COUNT(sales_stage) INTO vCheck FROM scmecu_probability_stage WHERE sales_stage = :NEW.sales_stage;
        IF vCheck > 1 THEN
            RAISE_APPLICATION_ERROR(-20000, 'Etapa de venta duplicada');
        END IF;
    END IF;

    END SCMECU_SALES_STAGE_UNIQUE_TRG
